import './MaskField.scss';

import type { ChangeEvent } from 'react';
import React, { forwardRef, useImperativeHandle, useRef } from 'react';

import { TextField } from '../TextField/TextField';
import type { OldMaskFieldProps } from './OldMaskField.types';

export const OldMaskField = forwardRef<HTMLInputElement, OldMaskFieldProps>(
	(
		{
			size = 'medium',
			autoComplete = 'off',
			inputClassName: externalInputClassName,
			fullWidth = false,
			error = false,
			disabled = false,
			dataTestId = 'TextField',
			isClickableAdornment = true,
			maskedInstance,
			onChange,
			...props
		},
		ref,
	) => {
		const localRef = useRef<HTMLInputElement>(null);
		useImperativeHandle(ref, () => localRef.current);

		const handleChange = (event: ChangeEvent<HTMLInputElement>): void => {
			const { value: updatedInputValue } = event.target;

			maskedInstance?.resolve(updatedInputValue);

			event.target.value = maskedInstance.value;

			onChange?.(event);
		};

		return (
			<div data-testid="MaskField">
				<TextField
					ref={localRef}
					size={size}
					autoComplete={autoComplete}
					inputClassName={externalInputClassName}
					fullWidth={fullWidth}
					error={error}
					disabled={disabled}
					dataTestId={dataTestId}
					isClickableAdornment={isClickableAdornment}
					onChange={handleChange}
					{...props}
				/>
			</div>
		);
	},
);
